import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, LayoutGrid, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminSections = () => {
  const [sections, setSections] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchSections = async () => {
    try {
      const res: any = await AdminService.getAllSections();
      // Accessing res.data.data to match your API response structure
      const actualData = res.data?.data || [];
      setSections(Array.isArray(actualData) ? actualData : []);
    } catch (err) {
      toast.error("Sections Sync Failed");
      setSections([]);
    }
  };

  useEffect(() => { fetchSections(); }, []);

  const handleDelete = async (sectionId: string) => {
    if (!sectionId) return toast.error("Invalid Section ID");
    if (!window.confirm(`Permanently delete section ${sectionId}?`)) return;

    try {
      await AdminService.deleteSection(sectionId);
      toast.success("Section Purged");
      fetchSections();
    } catch (err) {
      toast.error("Delete Failed: Linked artworks may exist");
    }
  };

  const filtered = sections.filter(s => 
    (s.Section_Title || "").toLowerCase().includes(search.toLowerCase()) || 
    (s.Section_ID || "").toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic text-white">
            Archive <span className="text-primary">Sections</span>
          </h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Structural Segments</p>
        </div>
        <Link to="/admin/sections/add" className="bg-primary text-black px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-white transition-all shadow-xl">
          <Plus size={16} /> New Section
        </Link>
      </div>

      {/* Search Bar */}
      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
        <input 
          placeholder="Filter by Section ID or Title..." 
          className="w-full bg-white/5 border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold transition-all"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filtered.map((sec: any) => (
          <div key={sec._id} className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 flex items-center justify-between group shadow-sm hover:border-primary/20 transition-all">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-primary/10 rounded-xl">
                <LayoutGrid className="text-primary" size={20} />
              </div>
              <div className="min-w-0">
                <span className="text-[9px] bg-primary/20 text-primary px-2 py-0.5 rounded font-black mb-1 inline-block uppercase tracking-tighter">
                  {sec.Section_ID}
                </span>
                <h4 className="font-black uppercase text-xs italic truncate text-white">
                  {sec.Section_Title || 'Untitled Section'}
                </h4>
                <p className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">
                  Order: {sec.Section_Order || '0'} • Book: {sec.Book_ID || 'N/A'}
                </p>
              </div>
            </div>
            
            <div className="flex gap-2">
              <Link 
                to={`/admin/sections/edit/${sec.Section_ID}`} 
                className="px-4 py-3 bg-white/5 rounded-xl text-[9px] font-black uppercase text-white hover:bg-white hover:text-black transition-all"
              >
                Modify
              </Link>
              <button 
                onClick={() => handleDelete(sec.Section_ID)}
                className="p-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"
              >
                <Trash2 size={16}/>
              </button>
            </div>
          </div>
        ))}

        {filtered.length === 0 && (
          <div className="col-span-full py-20 text-center bg-white/5 rounded-[2.5rem] border border-dashed border-white/10">
            <p className="text-gray-500 font-black uppercase text-[10px] tracking-widest">No matching sections found in archive</p>
          </div>
        )}
      </div>
    </div>
  );
};
